head.b:skin:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  background-color: #221f1f;
  color: #ffffff;
  font-family: 'Poppins', sans-serif;
  line-height: 1.6;
}

.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}

/* Header */
#header-wrapper {
  background: linear-gradient(135deg, rgba(34,31,31,0.95) 0%, rgba(20,20,20,0.98) 100%);
  padding: 1.5rem 0;
  border-bottom: 3px solid #e50914;
  position: sticky;
  top: 0;
  z-index: 1000;
}

#header h1 {
  color: #e50914;
  font-size: 2.5rem;
  margin: 0;
}

#header h1 a {
  color: #e50914;
  text-decoration: none;
  transition: all 0.3s ease;
}

#header h1 a:hover {
  color: #ffc107;
}

.blog-description {
  color: #999;
  font-size: 1rem;
  margin-top: 0.5rem;
}

/* Main Layout */
.main-wrapper {
  display: grid;
  grid-template-columns: 1fr 320px;
  gap: 2rem;
  padding: 2rem 0;
}

.content-wrapper {
  background: transparent;
}

.sidebar-wrapper {
  background: transparent;
}

/* Posts */
.post {
  background: #2f2f2f;
  border-radius: 10px;
  padding: 2rem;
  margin-bottom: 2rem;
  border: 1px solid #404040;
  box-shadow: 0 4px 15px rgba(0,0,0,0.3);
}

.post-title {
  color: #e50914;
  font-size: 1.8rem;
  margin-bottom: 0.75rem;
  line-height: 1.3;
}

.post-title a {
  color: #e50914;
  text-decoration: none;
  transition: all 0.3s ease;
}

.post-title a:hover {
  color: #ffc107;
}

.post-meta {
  color: #999;
  font-size: 0.95rem;
  margin-bottom: 1.5rem;
  border-bottom: 1px solid #404040;
  padding-bottom: 1rem;
}

.post-body {
  color: #e0e0e0;
  line-height: 1.8;
  margin-bottom: 1.5rem;
}

.post-body img {
  max-width: 100%;
  height: auto;
  border-radius: 8px;
  margin: 1rem 0;
}

.post-labels {
  margin-top: 1rem;
}

.label {
  display: inline-block;
  background: #e50914;
  color: white;
  padding: 0.4rem 0.8rem;
  border-radius: 4px;
  margin: 0.25rem 0.5rem 0.25rem 0;
  font-size: 0.85rem;
  text-decoration: none;
  transition: all 0.3s ease;
}

.label:hover {
  background: #ffc107;
  color: black;
}

/* Widgets */
.widget {
  background: #2f2f2f;
  border-radius: 10px;
  padding: 1.5rem;
  margin-bottom: 1.5rem;
  border: 1px solid #404040;
  box-shadow: 0 4px 15px rgba(0,0,0,0.3);
}

.widget h2 {
  color: #e50914;
  font-size: 1.3rem;
  margin-bottom: 1.25rem;
  padding-bottom: 0.75rem;
  border-bottom: 2px solid #e50914;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.widget ul {
  list-style: none;
}

.widget li {
  padding: 0.65rem 0;
  border-bottom: 1px solid #404040;
}

.widget li:last-child {
  border-bottom: none;
}

.widget a {
  color: #e0e0e0;
  text-decoration: none;
  transition: all 0.3s ease;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.widget a:hover {
  color: #e50914;
  padding-left: 0.5rem;
}

/* Footer */
#footer-wrapper {
  background: linear-gradient(135deg, rgba(34,31,31,0.95) 0%, rgba(20,20,20,0.98) 100%);
  border-top: 3px solid #e50914;
  padding: 2rem 0 1rem;
  margin-top: 3rem;
}

.footer-content {
  text-align: center;
  color: #999;
}

.footer-content h2 {
  color: #e50914;
  font-size: 1.5rem;
  margin-bottom: 0.5rem;
}

.footer-content p {
  margin-bottom: 0.5rem;
}

.social-links {
  display: flex;
  justify-content: center;
  gap: 1rem;
  margin: 1rem 0;
}

.social-links a {
  color: #999;
  text-decoration: none;
  transition: all 0.3s ease;
}

.social-links a:hover {
  color: #e50914;
}

.footer-bottom {
  border-top: 1px solid #404040;
  padding-top: 1rem;
  margin-top: 1rem;
  font-size: 0.9rem;
}

/* Responsive */
@media (max-width: 768px) {
  .main-wrapper {
    grid-template-columns: 1fr;
  }

  #header h1 {
    font-size: 1.8rem;
  }

  .post {
    padding: 1.25rem;
  }

  .post-title {
    font-size: 1.4rem;
  }
}

/* Buttons */
button, .btn {
  background: #e50914;
  color: white;
  padding: 0.75rem 1.5rem;
  border: none;
  border-radius: 5px;
  cursor: pointer;
  font-weight: 600;
  transition: all 0.3s ease;
  text-decoration: none;
  display: inline-block;
}

button:hover, .btn:hover {
  background: #ffc107;
  color: black;
  transform: scale(1.05);
}

/* Links */
a {
  color: #e50914;
  transition: all 0.3s ease;
}

a:hover {
  color: #ffc107;
}

body.script:
// Back to top button
var backToTopBtn = document.createElement('button');
backToTopBtn.id = 'backToTopBtn';
backToTopBtn.innerHTML = '↑';
backToTopBtn.style.cssText = 'position: fixed; bottom: 30px; right: 30px; background: #e50914; color: white; border: none; border-radius: 50%; width: 50px; height: 50px; font-size: 1.5rem; cursor: pointer; display: none; z-index: 999; box-shadow: 0 4px 15px rgba(229, 9, 20, 0.4);';
document.body.appendChild(backToTopBtn);

window.addEventListener('scroll', function() {
  if (window.pageYOffset > 300) {
    backToTopBtn.style.display = 'block';
  } else {
    backToTopBtn.style.display = 'none';
  }
});

backToTopBtn.addEventListener('click', function() {
  window.scrollTo({top: 0, behavior: 'smooth'});
});

// Smooth scroll for links
document.querySelectorAll('a[href^="#"]').forEach(function(anchor) {
  anchor.addEventListener('click', function(e) {
    e.preventDefault();
    var target = document.querySelector(this.getAttribute('href'));
    if (target) {
      target.scrollIntoView({behavior: 'smooth'});
    }
  });
});
